/**
 * esbuild wrapper for lazy ESM bundles.
 *
 * Uses a resolve plugin to externalize parent bundle specifiers BEFORE
 * alias resolution — working around esbuild's "alias takes precedence
 * over external" behavior.
 *
 * Usage:
 *   node esm_lazy_bundle.mjs <entry.js> <externals.json> <aliases.json>
 *
 * - entry.js:       esbuild entry point (generated by Python)
 * - externals.json: array of parent module specifiers to externalize
 * - aliases.json:   object of {specifier: path} alias mappings
 *
 * Writes bundled ESM to stdout.
 */
import { build } from "esbuild";
import { readFileSync } from "node:fs";

const [entryPath, externalsPath, aliasesPath] = process.argv.slice(2);
const parentSpecifiers = new Set(JSON.parse(readFileSync(externalsPath, "utf-8")));
const aliases = JSON.parse(readFileSync(aliasesPath, "utf-8"));

const result = await build({
    entryPoints: [entryPath],
    bundle: true,
    format: "esm",
    minify: true,
    keepNames: true,
    target: "es2022",
    write: false,
    external: ["@odoo/*", "luxon", "dompurify", "bootstrap", "/web/static/lib/*"],
    alias: aliases,
    resolveExtensions: [".js", ".mjs", ".json"],
    plugins: [{
        name: "externalize-parent",
        setup(b) {
            // Intercept bare specifier resolution BEFORE aliases.
            // If the specifier matches a parent module, mark external.
            b.onResolve({ filter: /^@/ }, (args) => {
                if (parentSpecifiers.has(args.path)) {
                    return { path: args.path, external: true };
                }
                return undefined; // fall through to alias resolution
            });
        },
    }],
});

process.stdout.write(result.outputFiles[0].text);
